10	 *
11	 * 候选人实现要求：
12	 * 每个 job 按序执行 PHASES 中的 4 个阶段，每阶段：
13	 * 1. 等待 PHASE_DELAY_MS 毫秒（模拟处理耗时）
14	 * 2. 更新 MongoDB Job.phases（push { name, status: 'completed', completedAt: now }）
15	 * 3. 通过 eventBus 发送进度事件，让 WS Server 转发给客户端：
16	 *    eventBus.emit(`job:${job.data.jobId}`, {
17	 *      jobId: job.data.jobId,
18	 *      phase: phaseName,
19	 *      status: 'completed',
20	 *      progress: Math.round(((phaseIndex + 1) / PHASES.length) * 100),
21	 *      log: `Phase ${phaseName} completed`
22	 *    })
23	 * 4. 全部阶段完成后更新 Job.status = 'completed'
24	 * 5. 发生错误时更新 Job.status = 'failed' 并 eventBus.emit 带 status: 'failed'
25	 */
26	const processJob = async (job) => {
27	  // TODO: 实现 4-Phase 流水线处理逻辑
28	  const { jobId } = job.data;
29	  // eslint-disable-next-line no-void
30	  void jobId;
31	  // eslint-disable-next-line no-void
32	  void PHASES;
33	  // eslint-disable-next-line no-void
34	  void PHASE_DELAY_MS;
35	  // eslint-disable-next-line no-void
36	  void eventBus;
37	};
38	
39	/**
40	 * 启动 BullMQ Worker
41	 * 在 src/index.js 中调用 startWorker()
42	 */
43	const startWorker = () => {
44	  const worker = new Worker('job-pipeline', processJob, {
45	    connection: { url: config.redis.url },
46	  });
47	
